import { GoogleGenAI } from "@google/genai";
import { AnalysisResult, SearchAnalysisResult, GroundingChunk, PresidentialProfile, Incident, Candidate } from "../types";

// Initialize Gemini Client
// API Key must be set in the environment variables as API_KEY
// Safely check for process to avoid browser ReferenceErrors
const apiKey = (typeof process !== 'undefined' && process.env && process.env.API_KEY) || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to reliably extract and parse JSON from model output
const parseJSON = (text: string): any => {
  try {
    let clean = text.replace(/```json/gi, '').replace(/```/g, '').trim();
    const firstBrace = clean.indexOf('{');
    const lastBrace = clean.lastIndexOf('}');
    const firstBracket = clean.indexOf('[');
    const lastBracket = clean.lastIndexOf(']');

    // Check if it's an array or object and extract accordingly
    if (firstBracket !== -1 && lastBracket !== -1 && (firstBracket < firstBrace || firstBrace === -1)) {
        clean = clean.substring(firstBracket, lastBracket + 1);
    } else if (firstBrace !== -1 && lastBrace !== -1) {
        clean = clean.substring(firstBrace, lastBrace + 1);
    }

    return JSON.parse(clean);
  } catch (error) {
    console.error("JSON Parse Error:", error);
    throw error;
  }
};

export const fetchRecentIncidents = async (): Promise<Incident[]> => {
  if (!apiKey) return [];

  const prompt = `
    Search for the latest verifiable political and security incidents in Uganda from the last 72 hours.

    **Focus Sources:** Daily Monitor, New Vision, The Observer, Nile Post, Uganda Radio Network, NTV Uganda.

    **Target Events:** 
    - Political rallies blocked or disrupted.
    - Arrests of opposition figures or activists.
    - Riots, protests, or civil unrest.
    - Violence involved security forces.

    **Output Requirement:**
    1. Find 5 distinct, confirmed events.
    2. Format strictly as a JSON array of Incident objects.
    3. If specific lat/long is unknown, use the approximate coordinates for the District or Town mentioned.

    JSON Structure for each item:
    {
      "id": "generate_unique_string",
      "date": "YYYY-MM-DD",
      "location": "City/Town/District Name",
      "latitude": Number,
      "longitude": Number,
      "type": "Violence" | "Protest" | "Arrest" | "Intimidation" | "Rally",
      "fatalities": Number,
      "injuries": Number,
      "description": "Brief summary (max 20 words).",
      "verified": true,
      "osintReport": {
         "sourceReliability": "A - Completely Reliable",
         "credibilityScore": 90,
         "verifiedSources": ["Source Name 1", "Source Name 2"],
         "aiAnalysis": "Verification summary based on search results."
      }
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const jsonText = response.text;
    if (!jsonText) return [];

    const data = parseJSON(jsonText);
    if (Array.isArray(data)) {
        return data as Incident[];
    }
    return [];

  } catch (error) {
    console.error("Fetch Live Incidents Error:", error);
    return [];
  }
};

export const fetchLiveCandidateStats = async (candidates: Candidate[]): Promise<Partial<Candidate>[]> => {
  if (!apiKey) return [];

  // Map to simple objects for the prompt to reduce token usage
