  const prompt = `
    Perform a real-time sentiment analysis for the 2026 Uganda Presidential Election context (last 14 days) for the following candidates:
    ${JSON.stringify(candidateList)}

    **Task:**
    1. Use Google Search to find the latest news, social media discourse, and polling data.
    2. For each candidate, estimate:
       - **sentimentScore**: 0 to 100 (Higher is positive).
       - **mentions**: A numeric estimate of "buzz" or mention volume (e.g., 500 to 50000).
       - **projectedVoteShare**: Estimated support percentage based on current political standing (Ensure total is approx 100% including others).

    **Output:**
    Return ONLY a JSON array of objects with the following fields for each candidate:
    [
      { "id": "candidate_id_from_input", "sentimentScore": 75, "mentions": 12000, "projectedVoteShare": 45.5 },
      ...
    ]
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const jsonText = response.text;
    if (!jsonText) return [];

    const data = parseJSON(jsonText);
    if (Array.isArray(data)) {
        return data;
    }
    return [];

  } catch (error) {
    console.error("Fetch Live Candidate Stats Error:", error);
    return [];
  }
};

export const analyzeIncidentReport = async (text: string): Promise<AnalysisResult> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please set process.env.API_KEY.");
  }

  const prompt = `
    Analyze this political incident report from Uganda.

    Report Text: "${text}"

    **INSTRUCTIONS:**
    1. Use Google Search to verify if this incident (or similar events in this location) has been reported in the news or reliable sources.
    2. Extract the following information strictly based on the text and your search findings.
    3. Return ONLY a valid JSON object (no markdown formatting) matching the structure below.

    **JSON Structure:**
    {
      "eventType": "String (e.g., Violence, Arrest, Intimidation, Rally, Unknown)",
      "location": "String (District, Constituency, or Town)",
      "actors": ["String (List of groups/people involved)"],
      "casualties": {
        "deaths": Number,
        "injuries": Number
      },
      "significanceScore": Number (1-10, where 10 is national crisis),
      "summary": "String (Brief 1-sentence summary of the event and verification status)"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const jsonText = response.text;
    if (!jsonText) {
      throw new Error("No response from Gemini.");
    }

    const data = parseJSON(jsonText) as AnalysisResult;

    // Extract grounding chunks (sources)
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const safeChunks: GroundingChunk[] = Array.isArray(chunks) ? chunks.map((c: any) => ({
        web: c.web ? { uri: c.web.uri, title: c.web.title } : undefined
    })).filter(c => c.web) : [];

    return {
        ...data,
        sources: safeChunks
    };

  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

