        const liveStats = await fetchLiveCandidateStats(MOCK_CANDIDATES);
        if (liveStats?.length > 0) {
            setPresidentialCandidates(prev => prev.map(p => {
                const fresh = liveStats.find(s => s.id === p.id);
                return fresh ? { ...p, ...fresh } : p;
