      }
  };

  const handleSeed = () => {
      seedDatabase(incidents, MOCK_CANDIDATES, PARLIAMENTARY_DATA);
  };

  const renderContent = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        const feedCutoff = new Date();
        feedCutoff.setHours(feedCutoff.getHours() - 72);

        return (
