  useEffect(() => {
    const today = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
    setDateStr(today);
    handleGenerate();
  }, []);

  const handleGenerate = async () => {
    setLoading(true);
    const incidentsSummary = incidents.slice(0, 5).map(i => `${i.type} in ${i.location}`).join('; ');
    const candidatesSummary = candidates.slice(0, 4).map(c => `${c.name}: ${c.projectedVoteShare}%`).join('; ');

