            <RefreshCw size={18} className={loading ? "animate-spin" : ""} />
            {loading ? 'Thinking...' : 'Refresh Briefing'}
          </button>
          <button onClick={handleDownloadPDF} className="p-2.5 bg-slate-700 hover:bg-slate-600 rounded-lg text-slate-300 transition-colors">
            <Download size={20} />
          </button>
          <button onClick={handlePrint} className="p-2.5 bg-slate-700 hover:bg-slate-600 rounded-lg text-slate-300 transition-colors">
            <Printer size={20} />
          </button>
        </div>
      </div>

      <div ref={contentRef} className="flex-grow bg-[#fdfbf7] text-slate-900 rounded-xl shadow-2xl overflow-hidden max-w-5xl mx-auto w-full border border-slate-200">
        {loading ? (
          <div className="h-[600px] flex flex-col items-center justify-center p-12">
             <div className="w-16 h-16 border-4 border-slate-200 border-t-purple-600 rounded-full animate-spin mb-8"></div>
             <h3 className="text-2xl font-playfair text-slate-600">Consulting Council...</h3>
          </div>
        ) : report ? (
          <div className="flex flex-col lg:flex-row h-full">
            <div className="lg:w-80 bg-[#f4f1ea] border-r border-slate-200 p-10 flex-shrink-0">
                <h4 className="font-sans font-bold text-red-700 text-xs uppercase tracking-widest mb-6 border-b border-red-200 pb-3">Executive Summary</h4>
                <div className="space-y-8">
