                        </div>
                    ))}
                </div>
            </div>

            <article className="flex-grow p-10 md:p-16 lg:p-20">
                <div className="max-w-3xl mx-auto">
                    <div className="flex items-center gap-3 text-slate-500 font-sans text-xs font-bold tracking-widest uppercase mb-8">
                        <span className="flex items-center gap-1"><Calendar size={12} /> {dateStr}</span>
                        <span className="text-slate-300">|</span>
                        <span className="text-purple-700">Confidential</span>
                    </div>
                    <h1 className="font-playfair text-4xl md:text-5xl font-bold text-slate-900 mb-10 leading-tight">{report.title}</h1>
                    <div 
                        className="prose prose-lg prose-slate font-merriweather text-slate-800 max-w-none prose-p:leading-8 prose-p:mb-6"
                        dangerouslySetInnerHTML={{ __html: report.content || "" }}
                    />
                </div>
            </article>
