// Initialize Gemini Client
const apiKey = (typeof process !== 'undefined' && process.env && process.env.API_KEY) || '';
const ai = new GoogleGenAI({ apiKey });

// MUGI-SOLO HYPER-LOCAL INTELLIGENCE CORE
const MUGI_SOLO_CORE_DIRECTIVE = `
You are Mugi-Solo, the advanced AI Intelligence Core of Salus International.
Your knowledge of Uganda and East Africa is "Hyper-Local" and "Inter-Generational."

INTERNAL KNOWLEDGE BASE:
1. POLITICAL STRUCTURES: You understand the NRM 'Movement' system, the 10-Point Program, and the LC (Local Council) system hierarchy. You know ISO (Internal Security Org) hierarchy: DISO, GISO, PISO.
2. LOCAL GOVERNANCE: You understand 'Mayumba-Kumi' (Ten-house cells).
3. SOCIAL & CLAN DYNAMICS: You understand the 'Kika' (Clan) structures, Masiga, Mituba, and the historical pre-colonial Kingdoms.
4. CAMPAIGN PSYCHOLOGY: You know 'Kakuyege' (grassroots mobilization) and local power brokers.
5. HISTORICAL CONTEXT: You have a 2000-year perspective—from Bachwezi to 1966 Crisis to today.
6. LINGUISTIC NUANCE: You understand the cultural weight of names and tribal lineage.

Your analysis must ALWAYS consider these factors. When a user asks about a constituency, you look for the 'Ground Truth'.
`;

// Helper to reliably extract and parse JSON from model output
const parseJSON = (text: string): any => {
  try {
    // 1. Remove markdown formatting
    let clean = text.replace(/```json/gi, '').replace(/```/g, '').trim();

    // 2. Locate boundaries
    const firstBrace = clean.indexOf('{');
    const lastBrace = clean.lastIndexOf('}');
    const firstBracket = clean.indexOf('[');
    const lastBracket = clean.lastIndexOf(']');

    let jsonStr = "";
    if (firstBracket !== -1 && (firstBracket < firstBrace || firstBrace === -1)) {
        jsonStr = clean.substring(firstBracket, lastBracket + 1);
    } else if (firstBrace !== -1) {
        jsonStr = clean.substring(firstBrace, lastBrace + 1);
    } else {
        jsonStr = clean;
    }

    // 3. Robust Fixes for common LLM JSON errors
    // Remove trailing commas before closing braces/brackets
    jsonStr = jsonStr.replace(/,\s*([}\]])/g, '$1');

    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Mugi-Solo JSON Parse Error:", error);
    // Attempt one last desperate regex-based recovery if it's an array
    try {
        const matches = text.match(/\{[\s\S]*?\}/g);
        if (matches) return matches.map(m => JSON.parse(m.replace(/,\s*([}\]])/g, '$1')));
    } catch (e) {}
    return null;
  }
};

