export const analyzePresidentialCandidate = async (name: string, party: string): Promise<PresidentialProfile | null> => {
  if (!apiKey) return null;
  const prompt = `${MUGI_SOLO_CORE_DIRECTIVE}
    Deep OSINT on: ${name} (${party}). Include lineage, regional standing, and 'Grand Strategy'.
    Focus on developments within the last 90 days.
    Return strictly JSON.`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] }
    });
    const data = parseJSON(response.text);
    if (!data) return null;
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    return { ...data, sources: chunks.map((c: any) => ({ web: c.web ? { uri: c.web.uri, title: c.web.title } : undefined })).filter((c:any) => c.web) };
  } catch (error) { return null; }
};

