export const chatWithAnalyst = async (history: any[], message: string) => {
  if (!apiKey) return "Mugi-Solo System Offline.";
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      history: history,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: MUGI_SOLO_CORE_DIRECTIVE
      }
    });
    const result = await chat.sendMessage({ message });
    const text = result.text;
    // If text looks like JSON, we just return it as a string to avoid rendering objects
    return typeof text === 'string' ? text : JSON.stringify(text);
  } catch (error) { return "Interference detected in the feed."; }
