Your analysis must ALWAYS consider these factors. When a user asks about a constituency, you look for the 'Ground Truth'.
`;

// Helper to reliably extract and parse JSON from model output
const parseJSON = (text: string): any => {
  if (!text) return null;
  try {
    // 1. Remove markdown formatting
    let clean = text.replace(/```json/gi, '').replace(/```/g, '').trim();

    // 2. Locate boundaries
    const firstBrace = clean.indexOf('{');
    const lastBrace = clean.lastIndexOf('}');
    const firstBracket = clean.indexOf('[');
    const lastBracket = clean.lastIndexOf(']');

    let jsonStr = "";
    if (firstBracket !== -1 && (firstBracket < firstBrace || firstBrace === -1)) {
        jsonStr = clean.substring(firstBracket, lastBracket + 1);
    } else if (firstBrace !== -1) {
        jsonStr = clean.substring(firstBrace, lastBrace + 1);
    } else {
        jsonStr = clean;
    }

    if (!jsonStr) return null;

    // 3. Robust Fixes for common LLM JSON errors
    // Remove trailing commas before closing braces/brackets
    jsonStr = jsonStr.replace(/,\s*([}\]])/g, '$1');

    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Mugi-Solo JSON Parse Error:", error);
    return null;
  }
};

export const fetchRecentIncidents = async (): Promise<Incident[]> => {
  const prompt = `${MUGI_SOLO_CORE_DIRECTIVE}
    Search for latest political/security incidents in Uganda over the last 90 days.
    Provide a comprehensive list of verified and unverified reports including protests, arrests, and violence.
    Return strictly a JSON array of Incident objects. 
    IMPORTANT: Every object MUST have 'latitude' and 'longitude' (numeric). 
    If specific coordinates are unknown, use Uganda's center approx: lat 1.3733, lng 32.2903.
    Schema: {id, date, location, latitude, longitude, type, fatalities, injuries, description, verified}`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] }
    });
    return parseJSON(response.text) || [];
  } catch (error) { return []; }
};

