    Return strictly a JSON array of Incident objects.
    Schema: {id, date, location, latitude, longitude, type, fatalities, injuries, description, verified, osintReport: {sourceReliability, credibilityScore, verifiedSources, aiAnalysis, timeline}}`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] }
    });
    return parseJSON(response.text) || [];
  } catch (error) { return []; }
};

