  const prompt = `${MUGI_SOLO_CORE_DIRECTIVE}
    DEEP OSINT: ${name} (${party}). 
    Analyze ONLY the LAST 90 DAYS of activity.
    Include lineage, regional standing, and 'Grand Strategy' forecast.
    Return strictly JSON.`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] }
    });
