                  </div>
              </div>
          ) : (
             <div className="mb-4 text-[10px] text-orange-400 font-bold uppercase flex items-center gap-2">
                <AlertTriangle size={12} /> LOCAL OPS ONLY
             </div>
          )}
           <button onClick={onReturnToSite} className="w-full flex items-center gap-4 px-5 py-4 rounded-lg text-slate-500 hover:bg-slate-800 mb-4 transition-colors">
             <LogOut size={20} /> <span className="font-medium text-base">Terminate Session</span>
           </button>
          <div className="flex items-center gap-4 p-3 rounded-lg bg-slate-800/50">
            <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-blue-500 to-purple-500 ring-2 ring-blue-500/20"></div>
            <div><p className="text-sm font-bold text-white truncate">G-COMMAND</p><p className="text-[10px] text-slate-500 font-mono truncate">ID: SALUS-90-OPS</p></div>
          </div>
        </div>
      </aside>
      <div className="flex-1 flex flex-col lg:ml-72 transition-all duration-300 print:ml-0 print:w-full">
        <header className="h-20 bg-slate-900/80 backdrop-blur-md border-b border-slate-800 sticky top-0 z-40 px-8 flex items-center justify-between print:hidden">
