export const Dashboard: React.FC<DashboardProps> = ({ onReturnToSite }) => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // State for Data
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [presidentialCandidates, setPresidentialCandidates] = useState<Candidate[]>(MOCK_CANDIDATES);
  const [parliamentaryCandidates, setParliamentaryCandidates] = useState<ParliamentaryCandidate[]>(PARLIAMENTARY_DATA);
  const [isLoadingFeed, setIsLoadingFeed] = useState(true);

  // Connection State
  const [isFirestoreConnected, setIsFirestoreConnected] = useState(!!db);

  const [stats, setStats] = useState({
    violenceIndex: '0.0',
    activeIncidents: 0,
    daysToElection: 0,
    sentiment: 'Analyzing...',
    sentimentColor: 'text-slate-200'
  });

  // --- STRICT 90-DAY DATA FILTER ---
  const filterRecent = (data: any[]) => {
    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - 90);
    return data.filter(item => item.date && new Date(item.date) >= cutoff);
  };

  // --- 0. Fetch Verified Live Data (Gemini Grounding) ---
  useEffect(() => {
    const loadRealData = async () => {
      setIsLoadingFeed(true);
      try {
        const verifiedIncidents = await fetchRecentIncidents();
        const recentOnly = filterRecent(verifiedIncidents);

        if (recentOnly && recentOnly.length > 0) {
            setIncidents(prev => {
                const ids = new Set(prev.map(i => i.id));
                const newItems = recentOnly.filter(i => !ids.has(i.id));
                return filterRecent([...newItems, ...prev]);
            });
        }

        const liveStats = await fetchLiveCandidateStats(MOCK_CANDIDATES);
        if (liveStats && liveStats.length > 0) {
            setPresidentialCandidates(prev => {
                const statMap = new Map(liveStats.map(s => [s.id, s]));
                return prev.map(p => {
                    const fresh = statMap.get(p.id);
                    if (fresh) {
                        return { 
                            ...p, 
                            sentimentScore: fresh.sentimentScore !== undefined ? fresh.sentimentScore : p.sentimentScore,
                            mentions: fresh.mentions !== undefined ? fresh.mentions : p.mentions,
                            projectedVoteShare: fresh.projectedVoteShare !== undefined ? fresh.projectedVoteShare : p.projectedVoteShare
                        };
                    }
                    return p;
                });
            });
        }

      } catch (err) {
        console.error("Failed to fetch live data", err);
      } finally {
        setIsLoadingFeed(false);
      }
    };
    loadRealData();
  }, []);

  // --- 1. Firestore Subscriptions ---
  useEffect(() => {
    if (!db) {
        setIsFirestoreConnected(false);
        return;
    }

    const handlePermissionError = (error: any) => {
        if (error.code === 'permission-denied') {
            setIsFirestoreConnected(false);
        }
    };

    const unsubIncidents = subscribeToIncidents((data) => {
        const recentData = filterRecent(data);
        if (recentData.length > 0) {
            setIncidents(recentData);
            setIsLoadingFeed(false);
        }
    }, handlePermissionError);

    const unsubPresidential = subscribeToPresidential((data) => {
        if (data.length > 0) {
            setPresidentialCandidates(data);
        }
    }, handlePermissionError);

    const unsubParliamentary = subscribeToParliamentary((data) => {
        if (data.length > 0) {
            setParliamentaryCandidates(data);
        }
    }, handlePermissionError);

    return () => {
        unsubIncidents();
        unsubPresidential();
        unsubParliamentary();
    };
  }, []);

  // --- 2. Live WebSocket Feed ---
  useEffect(() => {
    const handleRealTimeIncident = (incident: Incident) => {
      const cutoff = new Date();
      cutoff.setDate(cutoff.getDate() - 90);
      if (new Date(incident.date) < cutoff) return;

      if (isFirestoreConnected && db) {
          addIncidentToDb(incident);
      } else {
          setIncidents(currentIncidents => filterRecent([incident, ...currentIncidents]));
      }
    };
    liveDataService.connect(handleRealTimeIncident);
    return () => { liveDataService.disconnect(handleRealTimeIncident); };
  }, [isFirestoreConnected]);

  // --- 3. Stats Calculation ---
  useEffect(() => {
    const targetDate = new Date('2026-01-14T00:00:00');
    const today = new Date();
    const diffTime = Math.abs(targetDate.getTime() - today.getTime());
    const days = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    const recentIncidents = filterRecent(incidents);
    const activeCount = recentIncidents.length;

    let totalSeverity = 0;
    recentIncidents.forEach(inc => {
        let baseScore = 1;
        if (inc.type === 'Violence') baseScore = 8;
        if (inc.type === 'Protest') baseScore = 5;
        if (inc.type === 'Arrest') baseScore = 4;
        if (inc.type === 'Intimidation') baseScore = 3;
        totalSeverity += baseScore + (Number(inc.fatalities || 0) * 5) + (Number(inc.injuries || 0) * 0.5);
    });

    const rawIndex = recentIncidents.length > 0 ? (totalSeverity / recentIncidents.length) * 1.5 : 0;
    const vIndex = Math.min(10, Math.max(0, rawIndex)).toFixed(1);

    const totalVoteShare = presidentialCandidates.reduce((acc, c) => acc + (c.projectedVoteShare || 0), 0);
    const weightedSentiment = presidentialCandidates.reduce((acc, c) => acc + ((c.sentimentScore || 0) * (c.projectedVoteShare || 0)), 0) / (totalVoteShare || 1);

    let sentLabel = 'Neutral';
    let sentColor = 'blue';
    if (weightedSentiment < 40) { sentLabel = 'Volatile'; sentColor = 'red'; }
    else if (weightedSentiment < 55) { sentLabel = 'Tense'; sentColor = 'orange'; }
    else if (weightedSentiment < 65) { sentLabel = 'Cautious'; sentColor = 'blue'; }
    else { sentLabel = 'Optimistic'; sentColor = 'green'; }

    setStats({
        violenceIndex: isNaN(Number(vIndex)) ? '0.0' : vIndex,
        activeIncidents: activeCount,
        daysToElection: isNaN(days) ? 0 : days,
        sentiment: sentLabel,
        sentimentColor: sentColor
    });

  }, [incidents, presidentialCandidates]);

  const handleUpdateIncidents = (updatedList: Incident[]) => {
      const recentList = filterRecent(updatedList);
      if (isFirestoreConnected && db) {
          if (recentList.length > incidents.length) {
              const newItems = recentList.filter(x => !incidents.find(u => u.id === x.id));
              newItems.forEach(i => addIncidentToDb(i));
          } else if (recentList.length < incidents.length) {
              const deletedIds = incidents.filter(x => !recentList.find(u => u.id === x.id)).map(x => x.id);
              deletedIds.forEach(id => deleteIncidentFromDb(id));
          }
      } else {
          setIncidents(recentList);
      }
  };

  const handleUpdatePresCandidates = (updatedList: Candidate[]) => {
      if (isFirestoreConnected && db) {
          if (updatedList.length > presidentialCandidates.length) {
             const newItems = updatedList.filter(x => !presidentialCandidates.find(u => u.id === x.id));
             newItems.forEach(i => addPresidentialToDb(i));
          } else if (updatedList.length < presidentialCandidates.length) {
             const deletedIds = presidentialCandidates.filter(x => !updatedList.find(u => u.id === x.id)).map(x => x.id);
             deletedIds.forEach(id => deletePresidentialFromDb(id));
          }
      } else {
          setPresidentialCandidates(updatedList);
      }
  };

  const handleUpdateParlCandidates = (updatedList: ParliamentaryCandidate[]) => {
      if (isFirestoreConnected && db) {
         if (updatedList.length > parliamentaryCandidates.length) {
             const newItems = updatedList.filter(x => !parliamentaryCandidates.find(u => u.id === x.id));
             newItems.forEach(i => addParliamentaryToDb(i));
         } else if (updatedList.length < parliamentaryCandidates.length) {
             const deletedIds = parliamentaryCandidates.filter(x => !updatedList.find(u => u.id === x.id)).map(x => x.id);
             deletedIds.forEach(id => deleteParliamentaryFromDb(id));
         }
      } else {
          setParliamentaryCandidates(updatedList);
      }
  };

  const handleSeed = () => {
      seedDatabase(incidents, MOCK_CANDIDATES, PARLIAMENTARY_DATA);
  };

  const renderContent = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return (
          <div className="space-y-8 animate-fade-in text-slate-200">
             {/* Hyper-Local Intel Status Bar */}
             <div className="bg-slate-900/50 border border-blue-500/30 rounded-xl p-4 flex items-center justify-between shadow-2xl">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-blue-500/20 rounded-lg text-blue-400">
                      <ShieldAlert size={20} />
                   </div>
                   <div>
                      <p className="text-xs font-bold text-blue-400 uppercase tracking-widest">High-Command Intelligence Active</p>
                      <p className="text-sm text-slate-300">Operational Window: Last 90 Days. Ground Truth Protocol V4.2 Engaged.</p>
                   </div>
                </div>
                <div className="hidden md:flex items-center gap-4 text-[10px] font-mono text-slate-500">
                   <span className="flex items-center gap-1"><History size={10}/> 90-DAY WINDOW: SYNCED</span>
                   <span className="flex items-center gap-1"><Database size={10}/> ASSET LEDGER: ONLINE</span>
                </div>
             </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              <StatCard title="Violence Index" value={stats.violenceIndex} icon={ShieldAlert} color="red" />
              <StatCard title="Active Reports (90d)" value={stats.activeIncidents} icon={Bell} color="orange" />
              <StatCard title="Election Countdown" value={`${stats.daysToElection} Days`} icon={Radio} color="blue" />
              <StatCard title="Voter Sentiment" value={stats.sentiment} icon={TrendingUp} color={stats.sentimentColor} />
            </div>

            <div onClick={() => setCurrentView(ViewState.DAILY_OPED)} className="bg-gradient-to-r from-purple-900/50 to-blue-900/50 border border-purple-500/30 rounded-xl p-6 cursor-pointer hover:border-purple-400 transition-all group shadow-xl">
                <div className="flex items-center gap-4">
                   <div className="p-3 bg-purple-500/20 rounded-full text-purple-300"><FileText size={24} /></div>
                   <div>
                      <h3 className="text-lg font-bold text-white group-hover:text-purple-300 transition-colors">Strategic Intelligence SitRep</h3>
                      <p className="text-slate-300 text-sm">Deep-dive analysis of recent nation-state trends and security posture.</p>
                   </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2">
                <ViolenceMap incidents={incidents} onUpdateIncidents={handleUpdateIncidents} />
              </div>
              <div className="lg:col-span-1">
                <div className="bg-slate-800 rounded-xl border border-slate-700 p-8 h-full shadow-lg">
                  <h3 className="text-xl font-semibold text-white mb-6">Intelligence Feed (90d)</h3>
                  <div className="space-y-6 overflow-y-auto max-h-[500px] custom-scrollbar">
                    {incidents.slice(0, 15).map(inc => (
                        <div key={inc.id} className="pb-4 border-b border-slate-700/50 last:border-0">
                            <p className="text-base text-white font-medium">{inc.location}</p>
                            <p className="text-sm text-slate-400 mt-1 line-clamp-2">{inc.description}</p>
                            <div className="flex justify-between items-center mt-2">
                                <span className="text-[10px] text-slate-500 uppercase font-mono">{inc.date} • {inc.type}</span>
                                {inc.osintReport && (
                                    <span className={`text-[9px] px-1.5 py-0.5 rounded border border-blue-500/30 text-blue-400 font-bold`}>
                                        OSINT VERIFIED
                                    </span>
                                )}
                            </div>
                        </div>
                    ))}
                    {incidents.length === 0 && <p className="text-slate-500 text-center italic py-10">No active incidents within 90-day window.</p>}
                  </div>
                </div>
              </div>
            </div>
            <CandidateList candidates={presidentialCandidates} onUpdateCandidates={handleUpdatePresCandidates} />
          </div>
        );
      case ViewState.VIOLENCE_MAP: return <ViolenceMap incidents={incidents} onUpdateIncidents={handleUpdateIncidents} fullScreen />;
      case ViewState.ELECTION_MAP: return <ConstituencyMap candidates={parliamentaryCandidates} onUpdateCandidates={handleUpdateParlCandidates} />;
      case ViewState.CANDIDATES: return <CandidateList candidates={presidentialCandidates} onUpdateCandidates={handleUpdatePresCandidates} />;
      case ViewState.ANALYSIS: return <ReportAnalyzer />;
      case ViewState.PARLIAMENTARY: return <ParliamentaryAnalytics candidates={parliamentaryCandidates} onUpdateCandidates={handleUpdateParlCandidates} />;
      case ViewState.DAILY_OPED: return <DailyOpEd incidents={incidents} candidates={presidentialCandidates} />;
      case ViewState.COUNTRIES: return <CountryLedger />;
      default: return <div>Page not found</div>;
    }
  };

  const menuGroups = [
    {
      label: 'Intelligence Hub',
      icon: Target,
      items: [
        { id: ViewState.DASHBOARD, icon: LayoutDashboard, label: 'G-Command Overview' },
        { id: ViewState.COUNTRIES, icon: Globe, label: 'Continental Asset Ledger' },
        { id: ViewState.VIOLENCE_MAP, icon: ShieldAlert, label: 'Tactical Violence Logs' },
      ]
    },
    {
      label: 'Political Frontier',
      icon: Landmark,
      items: [
        { id: ViewState.CANDIDATES, icon: Users, label: 'Presidential Desk' },
        { id: ViewState.PARLIAMENTARY, icon: Briefcase, label: 'Legislative Analytics' },
        { id: ViewState.ELECTION_MAP, icon: Table, label: 'Constituency Matrix' },
      ]
    },
    {
      label: 'Deep Synthesis',
      icon: Cpu,
      items: [
        { id: ViewState.DAILY_OPED, icon: FileText, label: 'Strategic SitRep' },
        { id: ViewState.ANALYSIS, icon: BrainCircuit, label: 'Mugi-Solo Engine' }
      ]
    }
  ];

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 flex font-sans selection:bg-blue-500/30 relative overflow-hidden">
      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-slate-900 border-r border-slate-800 transform transition-transform duration-300 lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} print:hidden flex flex-col shadow-2xl`}>
        <div className="h-20 flex items-center px-8 border-b border-slate-800 shrink-0">
