            <div className="overflow-hidden">
                <p className="text-xs font-black text-white truncate uppercase tracking-tighter">ANALYST_PRIME</p>
                <div className="flex items-center gap-1.5">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <p className="text-[9px] text-slate-500 font-mono truncate">CLEARANCE: L5</p>
                </div>
