        <main className="p-8 flex-1 overflow-y-auto print:p-0 bg-[#020617] custom-scrollbar">
          <div className="max-w-7xl mx-auto h-full">
            {renderContent()}
          </div>
        </main>
      </div>

      <div className="print:hidden chatbot-container"><Chatbot /></div>
      {isMobileMenuOpen && <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-40 lg:hidden" onClick={() => setIsMobileMenuOpen(false)}></div>}
    </div>
  );
}

