      <div className="flex-1 flex flex-col lg:ml-72 transition-all duration-300 print:ml-0 print:w-full relative">
        <header className="h-20 bg-slate-950/80 backdrop-blur-xl border-b border-slate-800 sticky top-0 z-40 px-8 flex items-center justify-between print:hidden">
           <div className="flex items-center gap-4">
