           </div>

           <div className="flex items-center gap-8">
              <div className="relative hidden xl:block">
                 <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                 <input type="text" placeholder="Access Ground Truth Index..." className="bg-slate-900 border border-slate-800 rounded-lg pl-11 pr-6 py-2.5 text-xs text-slate-200 w-80 focus:border-blue-500 outline-none transition-all shadow-inner placeholder-slate-600" />
              </div>
              <div className="flex items-center gap-4">
                <div className="hidden md:flex flex-col items-end mr-2">
                   <span className="text-[10px] font-mono text-slate-500 uppercase tracking-tighter">Ground Truth Latency</span>
                   <span className="text-xs font-bold text-blue-400">14ms</span>
                </div>
                <button className="relative p-2.5 bg-slate-900 rounded-lg border border-slate-800 text-slate-400 hover:text-white transition-all hover:border-slate-600 group">
                    <Bell size={20} />
