// Fix: Export the Dashboard component as a named export to resolve the module error in App.tsx
export const Dashboard: React.FC<DashboardProps> = ({ onReturnToSite }) => {
  const [view, setView] = useState<ViewState>(ViewState.DASHBOARD);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [presCandidates, setPresCandidates] = useState<Candidate[]>(MOCK_CANDIDATES);
  const [parlCandidates, setParlCandidates] = useState<ParliamentaryCandidate[]>([]);

  useEffect(() => {
    // Connect to Firestore real-time streams
    const unsubIncidents = subscribeToIncidents(setIncidents);
    const unsubPres = subscribeToPresidential((data) => {
        if (data && data.length > 0) setPresCandidates(data);
    });
    const unsubParl = subscribeToParliamentary(setParlCandidates);

    return () => {
      unsubIncidents();
      unsubPres();
      unsubParl();
    };
  }, []);

  const renderView = () => {
    switch (view) {
      case ViewState.VIOLENCE_MAP:
        return <ViolenceMap incidents={incidents} fullScreen />;
      case ViewState.CANDIDATES:
        return <CandidateList candidates={presCandidates} />;
      case ViewState.ANALYSIS:
        return <ReportAnalyzer />;
      case ViewState.PARLIAMENTARY:
        return <ParliamentaryAnalytics candidates={parlCandidates} onUpdateCandidates={setParlCandidates} />;
      case ViewState.DAILY_OPED:
        return <DailyOpEd incidents={incidents} candidates={presCandidates} />;
      case ViewState.COUNTRIES:
        return <CountryLedger />;
      default:
        return (
          <div className="space-y-8 animate-fade-in">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              <StatCard title="Total Incidents" value={incidents.length} icon={AlertCircle} color="red" change="+12%" changeType="negative" />
              <StatCard title="Active Candidates" value={presCandidates.length + parlCandidates.length} icon={Users} color="blue" />
              <StatCard title="Avg Sentiment" value="58%" icon={BrainCircuit} color="purple" change="+2.4%" changeType="positive" />
              <StatCard title="Projected Turnout" value="62.5%" icon={Vote} color="green" />
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <ViolenceMap incidents={incidents.slice(0, 5)} />
              <CandidateList candidates={presCandidates.slice(0, 4)} />
            </div>
          </div>
        );
    }
  };

  const NavItem = ({ target, icon: Icon, label }: { target: ViewState; icon: any; label: string }) => (
    <button
      onClick={() => setView(target)}
      className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all w-full text-left ${
        view === target ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen bg-slate-950 flex">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col shrink-0">
        <div className="p-6 border-b border-slate-800 flex items-center gap-3">
          <BrainCircuit className="text-blue-500" size={32} />
          <span className="text-white font-bold tracking-tight">MUGI-SOLO</span>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <NavItem target={ViewState.DASHBOARD} icon={LayoutDashboard} label="Dashboard" />
          <NavItem target={ViewState.VIOLENCE_MAP} icon={Map} label="Incident Log" />
          <NavItem target={ViewState.CANDIDATES} icon={Users} label="Presidential" />
          <NavItem target={ViewState.PARLIAMENTARY} icon={Vote} label="Parliamentary" />
          <NavItem target={ViewState.ANALYSIS} icon={BrainCircuit} label="DeepMind Intel" />
          <NavItem target={ViewState.DAILY_OPED} icon={FileText} label="Strategy Briefs" />
          <NavItem target={ViewState.COUNTRIES} icon={Globe} label="Country Ledger" />
        </nav>

        <div className="p-4 border-t border-slate-800">
          <button 
            onClick={onReturnToSite}
            className="flex items-center gap-3 px-4 py-3 w-full rounded-lg text-slate-400 hover:bg-red-500/10 hover:text-red-400 transition-all"
          >
            <LogOut size={20} />
            <span className="font-medium">Exit High-Command</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-8 relative">
        <header className="flex justify-between items-center mb-8">
           <h1 className="text-2xl font-bold text-white uppercase tracking-wider flex items-center gap-3">
              <span className="w-2 h-8 bg-blue-600 rounded-full"></span>
              {view.replace('_', ' ')}
           </h1>
           <div className="flex items-center gap-4">
              <div className="text-right">
                 <p className="text-xs text-slate-500 font-bold uppercase">System Status</p>
                 <p className="text-sm text-green-400 font-mono">NOMINAL // SYNCED</p>
              </div>
              <div className="w-10 h-10 bg-slate-800 rounded-full border border-slate-700 flex items-center justify-center text-blue-400">
                 <Shield size={20} />
              </div>
           </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {renderView()}
        </div>
        <Chatbot />
      </main>
    </div>
  );
};
